options(stringsAsFactors=FALSE,warn=1)
suppressPackageStartupMessages({library(data.table);library(ggplot2)})
script_arg<-grep("^--file=",commandArgs(),value=TRUE);script_dir<-dirname(normalizePath(sub("^--file=","",script_arg[[1L]])))
source(file.path(script_dir,"_diagnostics_v2_common.R"));z<-read_diagnostics_config();cfg<-z$cfg
data_root<-normalizePath(cfg$project$data_root,winslash="/",mustWork=TRUE);v4<-file.path(data_root,"diagnostics_v4_cross_dataset_validation");v3<-file.path(data_root,"diagnostics_v3_remaining_datasets");cleaned<-file.path(data_root,"diagnostics_v2_marker_ready_cleaned")
replace_generated<-"--replace-generated-output"%in%commandArgs(trailingOnly=TRUE);report_path<-file.path(v4,"FINAL_EXTERNAL_SCRNA_VALIDATION_REPORT.md");if(file.exists(report_path)&&!replace_generated)stop("Output exists: ",report_path)
roles<-data.table(dataset_id=c("GSE154600","GSE158722","GSE147082","GSE151214","GSE154763"),dataset_role=c("primary_tumor_ecosystem","malignant_fluid_tumor_ecosystem","tumor_sensitivity_validation","normal_fallopian_tube_reference","author_annotated_myeloid_reference"),evidence_level=c("PRIMARY_SUPPORT","INCONCLUSIVE","SENSITIVITY_SUPPORT","NORMAL_REFERENCE","MYELOID_REFERENCE"),tumor_effect_aggregation=c(TRUE,TRUE,TRUE,FALSE,FALSE))
count_total<-function(ds){if(ds=="GSE147082")return(nrow(fread(file.path(v4,"GSE147082_refined","refined_cell_assignments.csv.gz"))));if(ds=="GSE151214")return(nrow(fread(file.path(v3,ds,"normal_reference_cell_assignments.csv.gz"))));if(ds=="GSE154763")return(nrow(fread(file.path(v4,"GSE154763_refined","author_annotation_with_refined_state.csv.gz"))));a<-fread(file.path(cleaned,ds,"cleaned_cell_assignments.csv.gz"));r<-fread(file.path(cleaned,ds,"removed_cells.csv.gz"));nrow(a)+nrow(r)}
roles[,n_total_cells:=vapply(dataset_id,count_total,integer(1))]
roles[,primary_use:=c("tumor macrophage/epithelial context","independent malignant-fluid replication if evaluable","tumor sensitivity validation","normal fallopian-tube background","author-driven myeloid state reference")]
roles[,exclusion:=c("None","Unresolved and non-high-confidence macrophages/epithelium","cluster 19 and unresolved cells","No tumor effect aggregation or tumor LR meta-analysis","No epithelial receiver, tumor effect aggregation, raw-count QC or inferCNV")]
fwrite(roles,file.path(v4,"final_external_scrna_dataset_manifest.csv"),na="NA")

repro<-fread(file.path(v4,"macrophage_state_reproducibility_matrix.csv"));wide<-dcast(repro,dataset_id+dataset_role+n_high_confidence_macrophages+n_evaluable_patients~state,value.var="state_status")
ctx<-fread(file.path(v4,"spp1_cd44_itgb1_context_by_sample.csv"));ctxsum<-ctx[,.(n_context_samples=sum(context_evaluable),epithelial_receiver_available=any(receiver_evaluable),CD44_median_positive=median(CD44_positive_fraction[receiver_evaluable],na.rm=TRUE),ITGB1_median_positive=median(ITGB1_positive_fraction[receiver_evaluable],na.rm=TRUE),copositive_median=median(CD44_ITGB1_copositive_fraction[receiver_evaluable],na.rm=TRUE),spearman_rho=first(spearman_rho),spearman_p=first(p_value),analysis_type=first(analysis_type)),by=dataset_id]
e<-merge(roles,wide[,.(dataset_id,n_high_confidence_macrophages,n_evaluable_patients,SPP1,C1QC,FOLR2)],by="dataset_id",all.x=TRUE);e<-merge(e,ctxsum,by="dataset_id",all.x=TRUE)
e[is.na(n_high_confidence_macrophages),n_high_confidence_macrophages:=repro[match(dataset_id,repro$dataset_id),n_high_confidence_macrophages]];e[is.na(n_evaluable_patients),n_evaluable_patients:=repro[match(dataset_id,repro$dataset_id),n_evaluable_patients]]
e[,epithelial_receiver_available:=fifelse(is.na(epithelial_receiver_available),FALSE,epithelial_receiver_available)]
e[,`:=`(SPP1_state_status=SPP1,C1QC_state_status=C1QC,FOLR2_state_status=FOLR2,CD44_receiver_status=fcase(!epithelial_receiver_available,"NOT_AVAILABLE",CD44_median_positive>=.1,"DETECTED",default="LOW_BACKGROUND"),ITGB1_receiver_status=fcase(!epithelial_receiver_available,"NOT_AVAILABLE",ITGB1_median_positive>=.1,"DETECTED",default="LOW_BACKGROUND"),sender_receiver_context_status=fcase(n_context_samples>=6 & is.finite(spearman_rho),"SAMPLE_LEVEL_ASSOCIATION",n_context_samples>0,"DESCRIPTIVE_COEXISTENCE",default="NOT_EVALUABLE"))]
e[,main_limitation:=fcase(dataset_id=="GSE158722","Only two evaluable high-confidence macrophage patients; no matched high-confidence epithelial receiver context",dataset_id=="GSE147082","Sensitivity cohort; four evaluable macrophage patients and descriptive receiver context only",dataset_id=="GSE151214","Normal reference only; cluster 18 contains mixed myeloid cells and is excluded from tumor effects",dataset_id=="GSE154763","Normalized-expression author myeloid reference only; no epithelial receiver or raw-count analysis",default="Five patient-level units; context correlation n<6")]
e[,eligible_for_primary_conclusion:=dataset_id%in%c("GSE154600","GSE158722","GSE147082") & SPP1_state_status%in%c("REPLICATED","SUPPORTIVE") & sender_receiver_context_status!="NOT_EVALUABLE"]
keep<-c("dataset_id","dataset_role","evidence_level","n_total_cells","n_high_confidence_macrophages","n_evaluable_patients","SPP1_state_status","C1QC_state_status","FOLR2_state_status","epithelial_receiver_available","CD44_receiver_status","ITGB1_receiver_status","sender_receiver_context_status","main_limitation","eligible_for_primary_conclusion")
fwrite(e[,..keep],file.path(v4,"external_scrna_evidence_matrix.csv"),na="NA")

x154<-fread(file.path(v4,"GSE154763_refined","author_annotation_with_refined_state.csv.gz"));myref<-x154[,.(n_cells=.N,n_patients=uniqueN(patient),n_samples=uniqueN(library_id),SPP1_program_median=median(SPP1_program),C1QC_program_median=median(C1QC_program),FOLR2_program_median=median(FOLR2_program),SPP1_positive_fraction=mean(SPP1_positive),None_fraction=mean(module_state=="None"),Mixed_fraction=mean(module_state=="Mixed"),dominant_refined_state=names(sort(table(module_state),decreasing=TRUE))[1]),by=cell_type_original]
fwrite(myref,file.path(v4,"myeloid_reference_summary.csv"),na="NA")
conc<-fread(file.path(v4,"GSE154763_refined","author_subtype_state_concordance.csv"));pc<-melt(conc,id.vars="cell_type_original",measure.vars=c("concordance_fraction","none_fraction","mixed_fraction"),variable.name="outcome",value.name="fraction")
p5<-ggplot(pc,aes(cell_type_original,fraction,fill=outcome))+geom_col(position="stack")+theme_bw()+theme(axis.text.x=element_text(angle=25,hjust=1))+labs(title="GSE154763 author subtype versus strict module state",x=NULL,y="cell fraction")
ggsave(file.path(v4,"05_gse154763_author_state_concordance.png"),p5,width=9,height=5,dpi=180)

cnv<-fread(file.path(v4,"GSE147082_refined","target_cluster_cnv_summary.csv"));r147<-fread(file.path(v4,"GSE147082_refined","target_cluster_review.csv"));s151<-fread(file.path(v4,"GSE151214_refined","myeloid_cluster18_subclustering.csv"))[,.N,by=refined_type]
nb<-fread(file.path(v4,"normal_background_summary.csv"));normal_spp1<-nb[final_cell_type=="C1QC_macrophage"&feature=="SPP1"]
g154spp1<-myref[grepl("Macro_SPP1",cell_type_original)];g154c1<-myref[grepl("Macro_C1QC",cell_type_original)]
repro_line<-function(ds,st){z<-repro[dataset_id==ds&state==st];paste0(z$state_status," (",z$n_positive_patients,"/",z$n_evaluable_patients," evaluable patients; ",ifelse(nzchar(z$positive_patients),z$positive_patients,"none"),")")}
ctx_line<-function(ds){z<-ctxsum[dataset_id==ds];if(!nrow(z))return("not evaluable");paste0(z$n_context_samples," samples; ",z$analysis_type,ifelse(is.finite(z$spearman_rho),paste0(", rho=",sprintf("%.3f",z$spearman_rho),", p=",sprintf("%.3g",z$spearman_p)),""))}
lines<-c("# Final external scRNA validation report","","## Scope and statistical boundary","","No whole-dataset reclustering or QC was repeated. All cross-dataset comparisons use within-dataset percentiles, positive fractions and patient/sample-level prevalence; raw module scores from different methods are never compared. GSE151214 and GSE154763 are references only and are excluded from tumor-effect aggregation.","","## 1. GSE147082 targeted annotation","",paste0("- Cluster 4: **",cnv[cluster==4,final_judgment],"**. CNV-equivalent intensity=",sprintf("%.4f",cnv[cluster==4,cnv_intensity]),", normal-stroma similarity=",sprintf("%.3f",cnv[cluster==4,correlation_to_normal_stroma]),", tumor-epithelial similarity=",sprintf("%.3f",cnv[cluster==4,correlation_to_tumor_epithelial]),"."),paste0("- Cluster 7: **",cnv[cluster==7,final_judgment],"** with ",cnv[cluster==7,cartilage_marker_support]," cartilage-program markers; its CNV-equivalent profile is more similar to normal stroma than tumor epithelium."),paste0("- Cluster 6: targeted subclustering yielded ",paste(r147[grepl("cluster_6_subcluster",target),paste0(decision," n=",n_cells)],collapse="; "),". It is no longer treated as ordinary T cells."),"- Cluster 19 remains Unresolved and is excluded from downstream proportion, state, LR and differential analyses.","","## 2. GSE151214 normal myeloid reference","",paste0("Cluster 18 split into ",paste(s151$refined_type,s151$N,sep=" n=",collapse="; "),". Macrophage_DC_mixed cells are not counted as pure macrophage background. Groups with fewer than 20 cells remain audited but are excluded from quantitative summaries."),if(nrow(normal_spp1))paste0("Normal C1QC macrophage SPP1 background across evaluable sample groups: median average expression=",sprintf("%.4f",normal_spp1$median_across_samples),", median positive fraction=",sprintf("%.3f",normal_spp1$median_positive_fraction),", n=",normal_spp1$n_evaluable_samples," samples.")else"Normal C1QC macrophage SPP1 background was not evaluable.","","## 3. GSE154763 author-driven state validation","",paste0("Strict lineage-specific thresholds assigned None to ",sum(x154$module_state=="None")," cells and Mixed to ",sum(x154$module_state=="Mixed")," cells; DC/Mast cells remain None. Author subtype remains primary."),paste0("Macro_SPP1 median SPP1 program=",sprintf("%.3f",g154spp1$SPP1_program_median)," versus Macro_C1QC=",sprintf("%.3f",g154c1$SPP1_program_median),"; Macro_C1QC median C1QC/FOLR2 programs=",sprintf("%.3f",g154c1$C1QC_program_median),"/",sprintf("%.3f",g154c1$FOLR2_program_median),". Cohort-level ordering supports the author labels, while strict cell-level concordance is partial."),"The P20190304 tumor/normal comparison is descriptive only; no inference is made from one paired patient.","","## 4. Macrophage-state reproducibility","",paste0("- GSE154600: SPP1 ",repro_line("GSE154600","SPP1"),"; C1QC ",repro_line("GSE154600","C1QC"),"; FOLR2 ",repro_line("GSE154600","FOLR2"),"."),paste0("- GSE158722: SPP1 ",repro_line("GSE158722","SPP1"),"; C1QC ",repro_line("GSE158722","C1QC"),"; FOLR2 ",repro_line("GSE158722","FOLR2"),"."),paste0("- GSE147082: SPP1 ",repro_line("GSE147082","SPP1"),"; C1QC ",repro_line("GSE147082","C1QC"),"; FOLR2 ",repro_line("GSE147082","FOLR2"),"."),"C1QC/FOLR2 frequently co-vary, whereas SPP1 shows dataset- and patient-dependent overlap, consistent with partially separated states along a continuum rather than mutually exclusive universal classes.","","## 5. SPP1-associated CD44/ITGB1-positive adhesion context","",paste0("- GSE154600: ",ctx_line("GSE154600"),"."),paste0("- GSE147082: ",ctx_line("GSE147082"),"."),paste0("- GSE158722: ",ctx_line("GSE158722")," because no matched high-confidence sender/receiver sample set passed both cell-count gates."),"These are sample-level co-occurrence descriptions. They are not evidence of a proven direct SPP1-ITGB1 ligand-receptor interaction or causal regulation.","","## 6. Evidence roles","","GSE154600 is the primary tumor support dataset; GSE147082 provides sensitivity support; GSE158722 is inconclusive under strict high-confidence gates; GSE151214 is a normal reference; GSE154763 is an author-annotated myeloid reference. Only the three tumor datasets are eligible for tumor conclusions, and eligibility still depends on their explicit state/context gates.","","## 7. Remaining limitations","","The analyses cannot prove direct receptor binding, directionality or causality; cannot treat cells as independent replicates; cannot infer GSE154763 raw-count QC/CNV; cannot recover GSE158722 unresolved cells into the validation; and cannot claim correlation significance when fewer than six evaluable samples are available.")
writeLines(lines,report_path,useBytes=TRUE)
